export { default as Map } from "./Map.vue";
export { default as MapMarker } from "./MapMarker.vue";
export { default as MarkerContent } from "./MarkerContent.vue";
export { default as MarkerLabel } from "./MarkerLabel.vue";
export { default as MarkerPopup } from "./MarkerPopup.vue";
export { default as MarkerTooltip } from "./MarkerTooltip.vue";
export { default as MapPopup } from "./MapPopup.vue";
export { default as MapControls } from "./MapControls.vue";
export { default as MapRoute } from "./MapRoute.vue";
export { default as MapArc } from "./MapArc.vue";
export { default as MapClusterLayer } from "./MapClusterLayer.vue";

export { useMap } from "./composables/use-map";
export { useResolvedTheme } from "./composables/use-resolved-theme";

export type {
  MapRef,
  MapViewport,
  MapArcDatum,
  MapArcEvent,
  MapArcLineLayout,
  MapArcLinePaint,
  Theme,
} from "./types";

import type { InjectionKey, Ref } from "vue";
import type { Map as MapLibreMap, Marker as MapLibreMarker } from "maplibre-gl";

export type MapContextValue = {
  map: Ref<MapLibreMap | null>;
  isLoaded: Ref<boolean>;
};

export const MapContextKey: InjectionKey<MapContextValue> =
  Symbol("MapContext");

export type MarkerContextValue = {
  marker: Ref<MapLibreMarker | null>;
  map: Ref<MapLibreMap | null>;
};

export const MarkerContextKey: InjectionKey<MarkerContextValue> =
  Symbol("MarkerContext");

import type {
  Map as MapLibreMap,
  LineLayerSpecification,
  MapMouseEvent,
} from "maplibre-gl";

export type Theme = "light" | "dark";

/** Map viewport state */
export type MapViewport = {
  /** Center coordinates [longitude, latitude] */
  center: [number, number];
  /** Zoom level */
  zoom: number;
  /** Bearing (rotation) in degrees */
  bearing: number;
  /** Pitch (tilt) in degrees */
  pitch: number;
};

/** Underlying MapLibre map instance, exposed via template ref. */
export type MapRef = MapLibreMap;

/** A single arc to render inside <MapArc :data="..." />. */
export type MapArcDatum = {
  /** Unique identifier for this arc. Required for hover state tracking and event payloads. */
  id: string | number;
  /** Start coordinate as [longitude, latitude]. */
  from: [number, number];
  /** End coordinate as [longitude, latitude]. */
  to: [number, number];
};

/** Event payload passed to MapArc interaction callbacks. */
export type MapArcEvent<T extends MapArcDatum = MapArcDatum> = {
  /** The arc datum that was hovered or clicked. */
  arc: T;
  /** Longitude of the cursor at the time of the event. */
  longitude: number;
  /** Latitude of the cursor at the time of the event. */
  latitude: number;
  /** The underlying MapLibre mouse event for advanced use cases. */
  originalEvent: MapMouseEvent;
};

export type MapArcLinePaint = NonNullable<LineLayerSpecification["paint"]>;
export type MapArcLineLayout = NonNullable<LineLayerSpecification["layout"]>;

import type { Map as MapLibreMap } from "maplibre-gl";
import type { MapArcLinePaint, MapViewport } from "./types";

export function getViewport(map: MapLibreMap): MapViewport {
  const center = map.getCenter();
  return {
    center: [center.lng, center.lat],
    zoom: map.getZoom(),
    bearing: map.getBearing(),
    pitch: map.getPitch(),
  };
}

export function mergeArcPaint(
  paint: MapArcLinePaint,
  hoverPaint: MapArcLinePaint | undefined,
): MapArcLinePaint {
  if (!hoverPaint) return paint;
  const merged: Record<string, unknown> = { ...paint };
  for (const [key, hoverValue] of Object.entries(hoverPaint)) {
    if (hoverValue === undefined) continue;
    const baseValue = merged[key];
    merged[key] =
      baseValue === undefined
        ? hoverValue
        : [
            "case",
            ["boolean", ["feature-state", "hover"], false],
            hoverValue,
            baseValue,
          ];
  }
  return merged as MapArcLinePaint;
}

export function buildArcCoordinates(
  from: [number, number],
  to: [number, number],
  curvature: number,
  samples: number,
): [number, number][] {
  const [x0, y0] = from;
  const [x2, y2] = to;
  const dx = x2 - x0;
  const dy = y2 - y0;
  const distance = Math.hypot(dx, dy);

  if (distance === 0 || curvature === 0) return [from, to];

  const mx = (x0 + x2) / 2;
  const my = (y0 + y2) / 2;
  const nx = -dy / distance;
  const ny = dx / distance;
  const offset = distance * curvature;
  const cx = mx + nx * offset;
  const cy = my + ny * offset;

  const points: [number, number][] = [];
  const segments = Math.max(2, Math.floor(samples));
  for (let i = 0; i <= segments; i += 1) {
    const t = i / segments;
    const inv = 1 - t;
    const x = inv * inv * x0 + 2 * inv * t * cx + t * t * x2;
    const y = inv * inv * y0 + 2 * inv * t * cy + t * t * y2;
    points.push([x, y]);
  }
  return points;
}

import { inject } from "vue";
import { MapContextKey, type MapContextValue } from "../context";

export function useMap(): MapContextValue {
  const ctx = inject(MapContextKey, null);
  if (!ctx) {
    throw new Error("useMap must be used within a Map component");
  }
  return ctx;
}

import { onBeforeUnmount, watch, type Ref } from "vue";
import type { Map as MapLibreMap } from "maplibre-gl";

export type LayerSetup = (map: MapLibreMap) => void | (() => void);

/**
 * Manages a custom MapLibre layer's lifecycle within a `<Map>`:
 * - Calls `setup` once the map is fully loaded.
 * - On theme switch, MapLibre's `setStyle` wipes our layers/sources but
 *   keeps our delegated event listeners. The composable tears down the
 *   previous setup (so cleanup can `map.off(...)` the stale listeners) and
 *   re-runs `setup` once the new style is loaded.
 * - Cleans up on unmount.
 *
 * `setup` may return a cleanup function. Removal of layers/sources should
 * be wrapped in try/catch (or guarded with `getLayer`/`getSource`) since
 * `setStyle` may have already removed them when cleanup runs.
 */
export function useMapLayer(
  map: Ref<MapLibreMap | null>,
  isLoaded: Ref<boolean>,
  setup: LayerSetup,
) {
  let cleanup: (() => void) | null = null;

  const teardown = () => {
    cleanup?.();
    cleanup = null;
  };

  watch(
    [map, isLoaded],
    ([m, loaded]) => {
      if (!m) {
        teardown();
        return;
      }
      if (loaded) {
        if (cleanup) return;
        const ret = setup(m);
        cleanup = typeof ret === "function" ? ret : null;
      } else {
        // setStyle wiped the style. Run cleanup so any `map.on(layerId, ...)`
        // delegated listeners get unregistered (they survive setStyle and
        // would otherwise accumulate across theme toggles).
        teardown();
      }
    },
    { immediate: true },
  );

  onBeforeUnmount(teardown);
}

import {
  onBeforeUnmount,
  shallowRef,
  watch,
  type MaybeRefOrGetter,
  toValue,
} from "vue";
import MapLibreGL, { type PopupOptions } from "maplibre-gl";

/**
 * Encapsulates MapLibre Popup creation, the Teleport target div, and the
 * reactive sync of `offset` / `maxWidth` while the popup is open.
 *
 * The caller decides *when* to instantiate the popup (e.g. attach to a
 * marker, or open it directly on the map) by calling `create()`.
 */
export function usePopup(options: MaybeRefOrGetter<PopupOptions | undefined>) {
  const container = document.createElement("div");
  const popup = shallowRef<MapLibreGL.Popup | null>(null);

  const create = (extra?: Partial<PopupOptions>) => {
    const opts = toValue(options) ?? {};
    const instance = new MapLibreGL.Popup({
      offset: 16,
      ...opts,
      ...extra,
      // closeButton is rendered by PopupShell, never by MapLibre itself
      closeButton: false,
    })
      .setMaxWidth(opts.maxWidth ?? "none")
      .setDOMContent(container);
    popup.value = instance;
    return instance;
  };

  watch(
    () => toValue(options)?.offset,
    (next) => {
      const p = popup.value;
      if (!p?.isOpen()) return;
      p.setOffset(next ?? 16);
    },
  );

  watch(
    () => toValue(options)?.maxWidth,
    (next) => {
      const p = popup.value;
      if (!p?.isOpen() || !next) return;
      p.setMaxWidth(next);
    },
  );

  onBeforeUnmount(() => {
    if (popup.value?.isOpen()) popup.value.remove();
    popup.value = null;
  });

  return { container, popup, create };
}

import {
  computed,
  onBeforeUnmount,
  onMounted,
  ref,
  toValue,
  type ComputedRef,
  type MaybeRefOrGetter,
} from "vue";
import type { Theme } from "../types";

function getDocumentTheme(): Theme | null {
  if (typeof document === "undefined") return null;
  if (document.documentElement.classList.contains("dark")) return "dark";
  if (document.documentElement.classList.contains("light")) return "light";
  return null;
}

function getSystemTheme(): Theme {
  if (typeof window === "undefined") return "light";
  return window.matchMedia("(prefers-color-scheme: dark)").matches
    ? "dark"
    : "light";
}

/**
 * Resolves the active theme from three sources, in priority order:
 *  1. `themeProp` (explicit override)
 *  2. `.dark` / `.light` class on `<html>` (compatible with next-themes,
 *     `useColorMode`, and any class-based theme switcher)
 *  3. OS preference (`prefers-color-scheme`)
 *
 * Watches the document class list and the system preference for changes.
 */
export function useResolvedTheme(
  themeProp?: MaybeRefOrGetter<Theme | undefined>,
): ComputedRef<Theme> {
  const docTheme = ref<Theme | null>(getDocumentTheme());
  const sysTheme = ref<Theme>(getSystemTheme());

  onMounted(() => {
    const obs = new MutationObserver(() => {
      docTheme.value = getDocumentTheme();
    });
    obs.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ["class"],
    });

    const mq = window.matchMedia("(prefers-color-scheme: dark)");
    const onChange = (e: MediaQueryListEvent) => {
      sysTheme.value = e.matches ? "dark" : "light";
    };
    mq.addEventListener("change", onChange);

    onBeforeUnmount(() => {
      obs.disconnect();
      mq.removeEventListener("change", onChange);
    });
  });

  return computed(() => toValue(themeProp) ?? docTheme.value ?? sysTheme.value);
}
